// MetricDetailPage collects data and returns the metric detail page component.
func MetricDetailPage(ctx context.Context, c *collector.DataCollector, h *collector.DataHistory, name string, basePath string) (templ.Component, error) {
	detail := c.CollectMetricDetail(ctx, name)
	if detail == nil {
		return ErrorPage(404, "Not Found", "Metric '"+name+"' not found", basePath), nil
	}

	// Build bucket chart for histograms
	var bucketChart chart.Data
	if detail.HistogramData != nil {
		bucketChart = buildBucketChartData(detail.HistogramData.Buckets)
	}

	// Build time series chart from history
	timeSeriesPoints := h.GetMetricTimeSeries(name)
	timeSeriesChart := buildMetricTimeSeriesChartData(timeSeriesPoints, name)
	hasTimeSeries := len(timeSeriesPoints) > 1

	return MetricDetailPageContent(detail, bucketChart, timeSeriesChart, hasTimeSeries, basePath), nil
}

